final class AppState: ObservableObject {
    @Published var portfolio = Portfolio.sample
    @Published var orders: [TradeOrder] = TradeOrder.sample
    @Published var quotes: [Quote] = Quote.sample
    @Published var account = Account.sample
    @Published var selectedSymbol: String = "AAPL"
    @Published var lastError: String?

    let apiClient = TradingAPIClient.shared
    let orderEngine = OrderEngine()
    let marketData = MarketDataService()

    private var cancellables = Set<AnyCancellable>()

    init() {
        marketData.quotesPublisher
            .receive(on: DispatchQueue.main)
            .sink { [weak self] quotes in
                self?.quotes = quotes
            }
            .store(in: &cancellables)

        marketData.startStreaming(symbols: portfolio.positions.map { $0.symbol } + ["AAPL", "MSFT", "NVDA", "TSLA"])
    }

    func placeOrder(symbol: String, side: OrderSide, type: OrderType, quantity: Int, limitPrice: Decimal? = nil) {
        guard quantity > 0 else {
            lastError = "Quantity must be greater than zero."
            return
        }

        let order = TradeOrder(
            id: UUID().uuidString,
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            status: .pending,
            createdAt: Date()
        )

        orders.insert(order, at: 0)

        orderEngine.execute(order: order, account: account, portfolio: portfolio, quotes: quotes) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let execution):
                    self?.applyExecution(execution)
                    self?.lastError = nil
                case .failure(let error):
                    self?.updateOrderStatus(orderId: order.id, status: .rejected)
                    self?.lastError = error.localizedDescription
                }
            }
        }
    }

    private func applyExecution(_ execution: TradeExecution) {
        if let idx = orders.firstIndex(where: { $0.id == execution.orderId }) {
            orders[idx].status = .filled
            orders[idx].filledQuantity = execution.quantity
            orders[idx].avgFillPrice = execution.price
            orders[idx].executedAt = execution.timestamp
        }

        portfolio.apply(execution: execution)
        account.apply(execution: execution)
    }

    private func updateOrderStatus(orderId: String, status: TradeOrderStatus) {
        if let idx = orders.firstIndex(where: { $0.id == orderId }) {
            orders[idx].status = status
        }
    }
}

