struct Position: Identifiable {
    let id = UUID()
    var symbol: String
    var quantity: Int
    var avgCost: Decimal
    var marketPrice: Decimal

    var marketValue: Decimal { Decimal(quantity) * marketPrice }
    var costBasis: Decimal { Decimal(quantity) * avgCost }
    var unrealizedPnL: Decimal { marketValue - costBasis }
}

struct Portfolio {
    var positions: [Position]

    var marketValue: Decimal {
        positions.reduce(0) { $0 + $1.marketValue }
    }

    static let sample = Portfolio(positions: [
        Position(symbol: "AAPL", quantity: 20, avgCost: 182.10, marketPrice: 189.32),
        Position(symbol: "MSFT", quantity: 10, avgCost: 418.22, marketPrice: 412.85),
        Position(symbol: "NVDA", quantity: 5, avgCost: 830.00, marketPrice: 870.12)
    ])

    mutating func apply(execution: TradeExecution) {
        guard let idx = positions.firstIndex(where: { $0.symbol == execution.symbol }) else {
            if execution.side == .buy {
                positions.append(Position(symbol: execution.symbol, quantity: execution.quantity, avgCost: execution.price, marketPrice: execution.price))
            }
            return
        }

        var position = positions[idx]
        let totalQty = position.quantity + (execution.side == .buy ? execution.quantity : -execution.quantity)

        if totalQty <= 0 {
            positions.remove(at: idx)
            return
        }

        if execution.side == .buy {
            let newCost = (position.avgCost * Decimal(position.quantity) + execution.price * Decimal(execution.quantity)) / Decimal(totalQty)
            position.avgCost = newCost
        }

        position.quantity = totalQty
        position.marketPrice = execution.price
        positions[idx] = position
    }
}

struct Account {
    var id: String
    var cash: Decimal
    var buyingPower: Decimal
    var dayPnL: Decimal
    var netLiquidation: Decimal

    static let sample = Account(id: "ACC-1024", cash: 25000, buyingPower: 50000, dayPnL: 1240.22, netLiquidation: 128560.44)

    mutating func apply(execution: TradeExecution) {
        let gross = execution.price * Decimal(execution.quantity)
        switch execution.side {
        case .buy:
            cash -= gross
        case .sell:
            cash += gross
        }
        buyingPower = cash * 2
        netLiquidation += (execution.side == .buy ? -gross : gross)
    }
}

