struct TradeExecution {
    let orderId: String
    let symbol: String
    let side: OrderSide
    let quantity: Int
    let price: Decimal
    let timestamp: Date
}

enum OrderSide: String {
    case buy, sell
}

enum OrderType: String {
    case market, limit
}

enum TradeOrderStatus: String {
    case pending, filled, rejected, canceled
}

final class OrderEngine {
    func execute(order: TradeOrder, account: Account, portfolio: Portfolio, quotes: [Quote], completion: @escaping (Result<TradeExecution, Error>) -> Void) {
        DispatchQueue.global(qos: .userInitiated).asyncAfter(deadline: .now() + 0.35) {
            guard let quote = quotes.first(where: { $0.symbol == order.symbol }) else {
                completion(.failure(NSError(domain: "Trade", code: 404, userInfo: [NSLocalizedDescriptionKey: "Quote not found."])))
                return
            }

            let executionPrice: Decimal
            switch order.type {
            case .market:
                executionPrice = order.side == .buy ? quote.ask : quote.bid
            case .limit:
                guard let limit = order.limitPrice else {
                    completion(.failure(NSError(domain: "Trade", code: 400, userInfo: [NSLocalizedDescriptionKey: "Limit price required."])))
                    return
                }
                if order.side == .buy {
                    guard quote.ask <= limit else {
                        completion(.failure(NSError(domain: "Trade", code: 409, userInfo: [NSLocalizedDescriptionKey: "Limit buy not executable at current ask."])))
                        return
                    }
                    executionPrice = quote.ask
                } else {
                    guard quote.bid >= limit else {
                        completion(.failure(NSError(domain: "Trade", code: 409, userInfo: [NSLocalizedDescriptionKey: "Limit sell not executable at current bid."])))
                        return
                    }
                    executionPrice = quote.bid
                }
            }

            completion(.success(TradeExecution(orderId: order.id, symbol: order.symbol, side: order.side, quantity: order.quantity, price: executionPrice, timestamp: Date())))
        }
    }
}

final class MarketDataService {
    @Published private(set) var quotes: [Quote] = Quote.sample
    var quotesPublisher: Published<[Quote]>.Publisher { $quotes }

    private var timer: AnyCancellable?

    func startStreaming(symbols: [String]) {
        timer?.cancel()
        timer = Timer.publish(every: 1.5, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self else { return }
                var updated = self.quotes
                for i in updated.indices {
                    let drift = Decimal(Double.random(in: -1.5...1.5))
                    updated[i].lastPrice += drift
                    updated[i].bid = updated[i].lastPrice - 0.03
                    updated[i].ask = updated[i].lastPrice + 0.03
                    updated[i].change += drift
                    updated[i].updatedAt = Date()
                }
                self.quotes = updated.filter { symbols.contains($0.symbol) }
            }
    }
}

final class TradingAPIClient {
    static let shared = TradingAPIClient()
    private init() {}

    func sendAuthorizedRequest(path: String, method: String = "GET", body: Data? = nil) async throws -> Data {
        guard let url = URL(string: "https://api.example.com/\(path)") else {
            throw URLError(.badURL)
        }

        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        if let token = KeychainService.shared.read(key: "auth_token") {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let http = response as? HTTPURLResponse, (200...299).contains(http.statusCode) else {
            throw NSError(domain: "API", code: 1, userInfo: [NSLocalizedDescriptionKey: "Request failed"])
        }
        return data
    }
}

final class KeychainService {
    static let shared = KeychainService()
    private init() {}

    func save(key: String, value: String) {
        let data = Data(value.utf8)
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }

    func read(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

extension Decimal {
    var formattedCurrency: String {
        let ns = NSDecimalNumber(decimal: self)
        return NumberFormatter.currency.string(from: ns) ?? "$0.00"
    }

    var formattedSignedCurrency: String {
        let ns = NSDecimalNumber(decimal: self)
        return NumberFormatter.signedCurrency.string(from: ns) ?? "+$0.00"
    }
}

extension NumberFormatter {
    static let currency: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.minimumFractionDigits = 2
        f.maximumFractionDigits = 2
        return f
    }()

    static let signedCurrency: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.positivePrefix = "+"
        f.negativePrefix = "-"
        f.minimumFractionDigits = 2
        f.maximumFractionDigits = 2
        return f
    }()
}